import { BUYBACK_OFFER_EXPIRED_CONTENT } from './buyback-offer-expired.content';
import { TICKET_CLOSED_CONTENT } from './ticket-closed.content';
import { BUYBACK_WEEKLY_EXTENSION_APPROVED_CONTENT } from './buyback-final-extension-approved.content';
import { BUYBACK_WEEKLY_EXTENSION_REJECTED_CONTENT } from './buyback-final-extension-rejected.content';
import { QUOTE_REQUEST_SUBMITTED_CONTENT } from './quote-request-submitted.content';
import { QUOTE_REQUEST_ADMIN_CONTENT } from './quote-request-admin.content';

const NOTIFICATION_CONTENT: Record<NotificationType, NotificationContentType> =
  {
    [NotificationType.QuoteRequestSubmitted]: QUOTE_REQUEST_SUBMITTED_CONTENT,
    [NotificationType.QuoteRequestAdminNotification]: QUOTE_REQUEST_ADMIN_CONTENT,
    [NotificationType.AuthenticationRequest]: AUTHENTICATION_REQUEST_CONTENT,
    [NotificationType.BuybackRequestMajorEvent]: BUYBACK_REQUEST_EVENT_CONTENT,
    [NotificationType.BuybackRequestMinorEvent]: BUYBACK_REQUEST_EVENT_CONTENT,
    [NotificationType.BuybackExtendReminder]: BUYBACK_EXTEND_REMINDER_CONTENT,
    [NotificationType.BuybackDeadlineComingUp]:
      BUYBACK_DEADLINE_COMING_UP_CONTENT,
    [NotificationType.BuybackUnsettled]: BUYBACK_UNSETTLED_CONTENT,
    [NotificationType.KycReminder]: KYC_REMINDER_CONTENT,
    [NotificationType.KycApproved]: KYC_APPROVED_CONTENT,
    [NotificationType.KycRejected]: KYC_REJECTED_CONTENT,
    [NotificationType.BuybackRequestAdminMinorEvent]:
      BUYBACK_REQUEST_ADMIN_EVENT_CONTENT,
    [NotificationType.BuybackRequestAdminMajorEvent]:
      BUYBACK_REQUEST_ADMIN_EVENT_CONTENT,
    [NotificationType.BuybackOfferExpired]: BUYBACK_OFFER_EXPIRED_CONTENT,
    [NotificationType.BuybackExtendedByAdmin]:
      BUYBACK_EXTENDED_BY_ADMIN_CONTENT,
    [NotificationType.BuybackAdminMinorEvent]: BUYBACK_ADMIN_EVENT_CONTENT,
    [NotificationType.BuybackAdminMajorEvent]: BUYBACK_ADMIN_EVENT_CONTENT,
    [NotificationType.BuybackFinalExtensionApproved]:
      BUYBACK_WEEKLY_EXTENSION_APPROVED_CONTENT,
    [NotificationType.BuybackFinalExtensionRejected]:
      BUYBACK_WEEKLY_EXTENSION_REJECTED_CONTENT,
    [NotificationType.TicketClosed]: TICKET_CLOSED_CONTENT,
  };

export function getNotificationContent<
  T extends NotificationType,
  M extends NotificationMedia,
>(type: T, media: M, data: NotificationData<T>) {
  return NOTIFICATION_CONTENT[type][media](data) as MEDIA_TYPE_TO_CONTENT<M>;
}

import { NotificationMedia } from './notification-media.const';
import { NotificationType } from './notification-type.const';

/**
 * Defines which notification media should be used for each notification type.
 */
export const NOTIFICATION_MEDIA_BY_TYPE: Record<
  NotificationType,
  NotificationMedia[]
> = {
  // Quote request submission
  [NotificationType.QuoteRequestSubmitted]: [
    NotificationMedia.Email,
    NotificationMedia.Phone,
  ],
  [NotificationType.QuoteRequestAdminNotification]: [
    NotificationMedia.Phone,
  ],

  // Buyback requests (seller)
  [NotificationType.BuybackRequestMajorEvent]: [
    NotificationMedia.Email,
    NotificationMedia.InApp,
  ],
  [NotificationType.BuybackRequestMinorEvent]: [NotificationMedia.InApp],

  // Buybacks (seller)
  [NotificationType.BuybackExtendReminder]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackDeadlineComingUp]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackUnsettled]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackExtendedByAdmin]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackOfferExpired]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackFinalExtensionApproved]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackFinalExtensionRejected]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],

  // KYC
  [NotificationType.KycReminder]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.KycApproved]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.KycRejected]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],

  // Authenticators
  [NotificationType.AuthenticationRequest]: [
    NotificationMedia.Email,
    NotificationMedia.InApp,
    NotificationMedia.Phone,
  ],

  // Admin
  [NotificationType.BuybackRequestAdminMinorEvent]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackRequestAdminMajorEvent]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackAdminMinorEvent]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  [NotificationType.BuybackAdminMajorEvent]: [
    NotificationMedia.InApp,
    NotificationMedia.Email,
  ],
  // Ticket
  [NotificationType.TicketClosed]: [NotificationMedia.InApp],
};

