  Entity,
  JoinColumn,
  ManyToOne,
  OneToMany,
  OneToOne,
} from 'typeorm';

import { BaseEntity } from '../utils';
import { UserEntity } from '@/db';
import { AssetEntity } from '@/db';
import { BuybackRequestEntity } from '@/db';
import { BuybackExtensionEntity } from '@/db';

export enum BuybackStatus {
  Quote = 'QUOTE',
  Active = 'ACTIVE',
  ExtensionRequested = 'EXTENSION_REQUESTED',
  ExtensionApproved = 'EXTENSION_APPROVED',
  Extended = 'EXTENDED',
  Unsettled = 'UNSETTLED',
  Closed = 'CLOSED',
  Rejected = 'REJECTED',
  OfferExpired = 'OFFER_EXPIRED',
  PaidBuyback = 'PAID_BUYBACK',
  SelfDropShipped = 'SELF_DROP_SHIPPED',
  CourierShipped = 'COURIER_SHIPPED',
  AssetPickedUp = 'ASSET_PICKED_UP',
}

export enum BuybackType {
  Buyback = 'BUYBACK',
  DirectSale = 'DIRECT_SALE',
}

export interface BuybackComputedDetails {
  outstandingAmountCents: number;
  tenure: number;

