export * from './GeneralTemplate';
export * from './OtpTemplate';
export * from './InviteTemplate';
export * from './QuoteRequestSubmittedTemplate';

import * as React from 'react';

import { TemplateLayout } from './components';

const COLORS = {
  text: '#000944',
  secondaryText: '#44403c',
  mutedBg: '#ede9e3',
  divider: '#d6d3d1',
};

type DetailRowProps = {
  label: string;
  value: string;
};

function DetailRow({ label, value }: DetailRowProps) {
  return (
    <>
      <table role="presentation" cellPadding="0" cellSpacing="0" width="100%">
        <tr>
          <td
            style={{
              fontFamily: 'Arial, sans-serif',
              fontSize: '14px',
              lineHeight: '150%',
              color: COLORS.secondaryText,
              paddingTop: '4px',
              paddingBottom: '4px',
              letterSpacing: '-0.14px',
            }}
          >
            {label}
          </td>
          <td
            align="right"
            style={{
              fontFamily: 'Arial, sans-serif',
              fontSize: '14px',
              fontWeight: 'bold',
              lineHeight: '150%',
              color: COLORS.secondaryText,
              paddingTop: '4px',
              paddingBottom: '4px',
              letterSpacing: '-0.14px',
              whiteSpace: 'nowrap',
              paddingLeft: '6px',
            }}
          >
            {value}
          </td>
        </tr>
      </table>
      <div
        style={{
          borderTop: `1px solid ${COLORS.divider}`,
          margin: '0',
          height: '1px',
          fontSize: '0',
          lineHeight: '0',
        }}
      />
    </>
  );
}

export type QuoteRequestSubmittedTemplateProps = {
  userLastName: string;
  offerTypeLabel: string;
  buybackRequestId: string;
  category: string;
  brand?: string;
  model?: string;
  reference?: string;
  condition?: string;
  additionalDetails?: string;
};

export function QuoteRequestSubmittedTemplate({
  userLastName,
  offerTypeLabel,
  buybackRequestId,
  category,
  brand,
  model,
  reference,
  condition,
  additionalDetails,
}: QuoteRequestSubmittedTemplateProps) {
  const rows: DetailRowProps[] = [
    { label: 'Offer type and ID', value: `${offerTypeLabel} – ${buybackRequestId.slice(0, 8).toUpperCase()}` },
    { label: 'Category', value: category },
  ];

  if (brand) rows.push({ label: 'Brand', value: brand });
  if (model) rows.push({ label: 'Model', value: model });
  if (reference) rows.push({ label: 'Reference', value: reference });
  if (condition) rows.push({ label: 'Condition', value: condition });
  if (additionalDetails) rows.push({ label: 'Additional details', value: additionalDetails });

  return (
    <TemplateLayout>
      {/* Title */}
      <p
        style={{
          margin: '0 0 20px 0',
          fontFamily: 'Arial, sans-serif',
          fontSize: '28px',
          fontWeight: 'bold',
          lineHeight: '150%',
          color: COLORS.text,
        }}
      >
        We have received your information
      </p>

      {/* Greeting and intro */}
      <p
        style={{
          margin: '0 0 8px 0',
          fontFamily: 'Arial, sans-serif',
          fontSize: '16px',
          lineHeight: '150%',
          color: COLORS.text,
        }}
      >
        <strong>Hello Mr. {userLastName},</strong>
      </p>
      <p
        style={{
          margin: '0 0 8px 0',
          fontFamily: 'Arial, sans-serif',
          fontSize: '16px',
          lineHeight: '150%',
          color: COLORS.text,
        }}
      >
        We have received your request for quotation. An indicative offer is being prepared and will be reviewed by our experts.
      </p>
      <p
        style={{
          margin: '0 0 32px 0',
          fontFamily: 'Arial, sans-serif',
          fontSize: '16px',
          lineHeight: '150%',
          color: COLORS.text,
        }}
      >
        Please find the details of your request below
      </p>

      {/* Details card */}
      <table
        role="presentation"
        cellPadding="0"
        cellSpacing="0"
        width="100%"
        style={{
          backgroundColor: COLORS.mutedBg,
          borderRadius: '16px',
          marginBottom: '32px',
        }}
      >
        <tr>
          <td style={{ padding: '20px' }}>
            {/* Card title */}
            <p
              style={{
                margin: '0 0 12px 0',
                fontFamily: 'Arial, sans-serif',
                fontSize: '16px',
                fontWeight: 'bold',
                lineHeight: '150%',
                color: COLORS.secondaryText,
                letterSpacing: '-0.16px',
              }}
            >
              Request Details
            </p>
            {rows.map((row) => (
              <DetailRow key={row.label} label={row.label} value={row.value} />
            ))}
          </td>
        </tr>
      </table>

      {/* Closing */}
      <p
        style={{
          margin: '0 0 8px 0',
          fontFamily: 'Arial, sans-serif',
          fontSize: '16px',
          lineHeight: '150%',
          color: COLORS.text,
        }}
      >
        {`We'll notify you again as soon as the offer it's ready.`}
      </p>
      <p
        style={{
          margin: '0 0 24px 0',
          fontFamily: 'Arial, sans-serif',
          fontSize: '16px',
          lineHeight: '150%',
          color: COLORS.text,
        }}
      >
        Please do not reply to this e-mail.
      </p>
      <p
        style={{
          margin: '0',
          fontFamily: 'Arial, sans-serif',
          fontSize: '16px',
          lineHeight: '150%',
          color: COLORS.text,
        }}
      >
        Best regards,
        <br />
        <strong>LuxFlow Team</strong>
      </p>
    </TemplateLayout>
  );
}

export default QuoteRequestSubmittedTemplate;

