import { AssetExtraItem, BuybackType } from '@/db';
import {
  NotificationContentType,
  NotificationData,
  NotificationMedia,
  NotificationType,
} from '../consts';

type Data = NotificationData<NotificationType.QuoteRequestSubmitted>;

const BUYBACK_TYPE_LABEL: Record<BuybackType, string> = {
  [BuybackType.Buyback]: 'Sale with Buyback',
  [BuybackType.DirectSale]: 'Direct Sale',
};

export const EXTRA_ITEM_LABEL: Record<AssetExtraItem, string> = {
  [AssetExtraItem.OriginalBox]: 'Original Box',
  [AssetExtraItem.OwnershipDocs]: 'Ownership Documents',
  [AssetExtraItem.AuthCert]: 'Authentication Certificate',
};

export function formatExtras(extras: Data['asset']['extras']): string | undefined {
  if (!extras) return undefined;
  const items = Object.entries(extras)
    .filter(([, enabled]) => enabled)
    .map(([key]) => EXTRA_ITEM_LABEL[key as AssetExtraItem] ?? key);
  return items.length ? items.join(', ') : undefined;
}

export function getBuybackTypeLabel(type: BuybackType): string {
  return BUYBACK_TYPE_LABEL[type];
}

export const QUOTE_REQUEST_SUBMITTED_CONTENT: NotificationContentType = {
  [NotificationMedia.Email]: (data: Data) => ({
    subject: 'LuxFlow: We have received your request for quotation',
    text: `Hello Mr. ${data.userLastName},\n\nWe have received your request for quotation. An indicative offer is being prepared and will be reviewed by our experts.\n\nWe'll notify you as soon as it's ready.\n\nThank you.\nLuxFlow Team`,
  }),
  [NotificationMedia.InApp]: (_data: Data) => ({
    title: 'Quote Request Received',
    body: 'We have received your request for quotation and will notify you when ready.',
  }),
  [NotificationMedia.Phone]: (data: Data) =>
    `Hello Mr. ${data.userLastName}, this is the LuxFlow team.\n\nWe have received your request for quotation. An indicative offer is being prepared and will be reviewed by our experts.\n\nWe'll notify you as soon as it's ready.\n\nThank you.`,
};

